	return dst
}

func cloneDialer(src *websocket.Dialer) *websocket.Dialer {
	if src == nil {
		return &websocket.Dialer{}
	}
	cp := *src
	cp.Subprotocols = append([]string(nil), src.Subprotocols...)
	return &cp
}

